#!/usr/bin/env node

/**
 * Aggregates per-package CHANGELOG.md files (generated by changesets)
 * into a single unified CHANGELOG.md at the repo root.
 *
 * Since all packages are in a changesets "fixed" group and share the
 * same version number, the root changelog presents a flat, deduplicated
 * list of changes per version â€” no per-package grouping.
 *
 * Run automatically via: pnpm version:bump
 * Run manually via:      node scripts/aggregate-changelog.js
 */

const fs = require('node:fs');
const path = require('node:path');

const root = path.resolve(__dirname, '..');

const PACKAGES = [
  'packages/components',
  'packages/tokens',
  'packages/icons',
  'packages/react',
  'packages/vue',
  'packages/angular',
  'packages/workbench',
  'packages/docs',
];

/**
 * Parse a changesets-generated CHANGELOG.md into structured releases.
 * Each release has a version, optional date, and sections (e.g. "Minor Changes").
 * Each section contains items, where an item may span multiple lines (indented continuations).
 */
function parseChangelog(raw) {
  const releases = [];
  const versionBlocks = raw.split(/^## /m).slice(1);

  for (const block of versionBlocks) {
    const lines = block.split('\n');
    const heading = lines[0].trim();
    const match = heading.match(/^(\d+\.\d+\.\d+(?:-[^\s]+)?)\s*(?:-\s*(.+))?$/);
    if (!match) continue;

    const version = match[1];
    const date = match[2]?.trim() || '';
    const sections = {};
    let currentSection = null;
    let currentItem = null;

    for (let i = 1; i < lines.length; i++) {
      const line = lines[i];

      // Section heading: ### Minor Changes, ### Patch Changes, etc.
      const sectionMatch = line.match(/^### (.+)/);
      if (sectionMatch) {
        currentSection = sectionMatch[1].trim();
        if (!sections[currentSection]) sections[currentSection] = [];
        currentItem = null;
        continue;
      }

      if (!currentSection) continue;

      // New item line: "- hash: description" or "- description"
      const itemMatch = line.match(/^- (.+)/);
      if (itemMatch) {
        currentItem = itemMatch[1];
        sections[currentSection].push(currentItem);
        continue;
      }

      // Continuation line (indented): belongs to the current item
      if (currentItem !== null && line.match(/^\s+/) && line.trim()) {
        const idx = sections[currentSection].length - 1;
        sections[currentSection][idx] += '\n' + line;
      }
    }

    releases.push({ version, date, sections });
  }

  return releases;
}

/**
 * Extract the commit hash prefix from a changeset entry line.
 * Entries look like: "5fd88a3: Some description" or "5fd88a3: - bullet list"
 * Returns the hash, or null if the line doesn't have one.
 */
function getHash(item) {
  const match = item.match(/^([a-f0-9]{7,}):/);
  return match ? match[1] : null;
}

/**
 * Check if an item is an "Updated dependencies" entry (internal dep noise).
 */
function isDepUpdate(item) {
  return /^Updated dependencies/i.test(item.trim());
}

// Read and parse all per-package changelogs
const allReleases = [];
for (const pkg of PACKAGES) {
  const changelogPath = path.join(root, pkg, 'CHANGELOG.md');
  if (!fs.existsSync(changelogPath)) continue;
  const raw = fs.readFileSync(changelogPath, 'utf-8');
  allReleases.push(...parseChangelog(raw));
}

// Group by version, merge sections, deduplicate entries
const versionMap = new Map();

for (const release of allReleases) {
  if (!versionMap.has(release.version)) {
    versionMap.set(release.version, { date: release.date, sections: {} });
  }
  const merged = versionMap.get(release.version);

  // Prefer a non-empty date
  if (release.date && !merged.date) {
    merged.date = release.date;
  }

  for (const [section, items] of Object.entries(release.sections)) {
    if (!merged.sections[section]) merged.sections[section] = [];

    for (const item of items) {
      // Skip internal dependency update noise
      if (isDepUpdate(item)) continue;

      // Deduplicate by hash prefix
      const hash = getHash(item);
      if (hash) {
        const alreadyExists = merged.sections[section].some(
          (existing) => getHash(existing) === hash,
        );
        if (alreadyExists) continue;
      } else {
        // No hash â€” deduplicate by exact text
        if (merged.sections[section].includes(item)) continue;
      }

      merged.sections[section].push(item);
    }
  }
}

// Sort versions descending
const sortedVersions = [...versionMap.keys()].sort((a, b) => {
  const ap = a.split('.').map(Number);
  const bp = b.split('.').map(Number);
  for (let i = 0; i < 3; i++) {
    if ((bp[i] || 0) !== (ap[i] || 0)) return (bp[i] || 0) - (ap[i] || 0);
  }
  return 0;
});

// Preferred section ordering
const SECTION_ORDER = ['Minor Changes', 'Patch Changes', 'Major Changes'];

// Build the unified changelog
const lines = ['# Cobalt Design System', ''];

for (const version of sortedVersions) {
  const { date, sections } = versionMap.get(version);
  const heading = date ? `## ${version} - ${date}` : `## ${version}`;
  lines.push(heading, '');

  // Sort sections in preferred order
  const sectionNames = Object.keys(sections).sort((a, b) => {
    const ai = SECTION_ORDER.indexOf(a);
    const bi = SECTION_ORDER.indexOf(b);
    return (ai === -1 ? 99 : ai) - (bi === -1 ? 99 : bi);
  });

  // Deduplicate across sections: if a hash appears in multiple sections,
  // keep it only in the highest-priority one (Minor > Patch > Major)
  const seenHashes = new Set();
  let hasContent = false;
  for (const section of sectionNames) {
    const items = sections[section].filter((item) => {
      const hash = getHash(item);
      if (hash && seenHashes.has(hash)) return false;
      if (hash) seenHashes.add(hash);
      return true;
    });
    if (items.length === 0) continue;
    hasContent = true;
    lines.push(`### ${section}`, '');
    for (const item of items) {
      lines.push(`- ${item}`);
    }
    lines.push('');
  }

  if (!hasContent) {
    lines.push('_No notable changes._', '');
  }
}

const output = lines.join('\n');
const outputPath = path.join(root, 'CHANGELOG.md');
fs.writeFileSync(outputPath, output, 'utf-8');

console.log(`Wrote unified changelog to ${outputPath}`);
console.log(`  ${sortedVersions.length} version(s) aggregated from ${PACKAGES.length} packages`);
